{
  "sentiment": "Positive" | "Neutral" | "Negative",
  "sentiment_score": <integer 1-10, where 10 is most positive>,
  "key_theme": "<main topic in 3-5 words>",
  "emotion": "<primary emotion: Happy | Angry | Disappointed | Satisfied | Frustrated | Delighted | Confused>",
  "needs_response": <true | false>,
  "response_urgency": "Low" | "Medium" | "High",
  "one_line_summary": "<summary in under 15 words>"
}

Platform: {{ $json.source }}
Star Rating: {{ $json.rating }}/5
Review Text: {{ $json.review_text }}

parameters.jsCode:
// Grab the original review fields from the SplitInBatches node
const review = $('🔄 Split Per Review').item.json;

// Grab OpenAI raw output
const aiRaw = $input.first().json?.text || '';

let sentiment = {};
try {
  const match = aiRaw.match(/\{[\s\S]*?\}/);
  sentiment = match ? JSON.parse(match[0]) : {};
} catch (e) {
  sentiment = {
    sentiment: 'Neutral',
    sentiment_score: 5,
    key_theme: 'Parse error',
    emotion: 'Unknown',
    needs_response: false,
    response_urgency: 'Low',
    one_line_summary: 'Could not parse AI response.'
  };
}

return [{
  json: {
    ...review,
    sentiment:          sentiment.sentiment        || 'Neutral',
    sentiment_score:    sentiment.sentiment_score  || 5,
    key_theme:          sentiment.key_theme        || '',
    emotion:            sentiment.emotion          || '',
    needs_response:     sentiment.needs_response   || false,
    response_urgency:   sentiment.response_urgency || 'Low',
    one_line_summary:   sentiment.one_line_summary || '',
    processed_at:       new Date().toISOString()
  }
}];

